      "content": "-- This is an idempotent script executed within the ETL flow to ensure presence of destination tables\nCREATE SCHEMA IF NOT EXISTS staging;\n\nCREATE TABLE IF NOT EXISTS staging.fx_rates_raw (\n    id SERIAL PRIMARY KEY,\n    base_currency VARCHAR(3),\n    target_currency VARCHAR(3),\n    exchange_rate DECIMAL(10,4),\n    retrieved_at TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS staging.shipping_logs_raw (\n    id SERIAL PRIMARY KEY,\n    vendor_id INT,\n    container_id VARCHAR(50),\n    delay_days INT,\n    ocean_freight_cost DECIMAL(10,2),\n    timestamp TIMESTAMP\n);\n",
